2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
18	const CURSED_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	
22	function withFirstInsurance(basePremium: number): number {
23	  return basePremium + basePremium * FIRST_INSURANCE_RATE;
24	}
25	
26	function premiumForTypeGroup(type: string, count: number): number {
27	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
28	    return withFirstInsurance(COMPONENT_BLOCK_BASE_PREMIUM);
29	  }
30	  return count * withFirstInsurance(BASE_PREMIUM_BY_ITEM_TYPE[type]);
31	}
32	
33	type Item = { type: string; cursed?: boolean; enchantment?: number };
34	
35	function surchargeRateForItem(item: Item): number {
36	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
37	  const enchantmentRate =
38	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
39	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
40	      : 0;
41	  return cursedRate + enchantmentRate;
42	}
43	
44	function surchargeForItem(item: Item): number {
45	  return BASE_PREMIUM_BY_ITEM_TYPE[item.type] * surchargeRateForItem(item);
46	}
47	
48	export function runScenario(scenario: any): unknown {
49	  const items: Item[] = scenario.items ?? [];
50	  const countsByType: Record<string, number> = {};
51	  let surchargesTotal = 0;
52	  for (const item of items) {
53	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
54	    surchargesTotal += surchargeForItem(item);
55	  }
56	  let itemsTotal = 0;
57	  for (const type of Object.keys(countsByType)) {
58	    itemsTotal += premiumForTypeGroup(type, countsByType[type]);
59	  }
60	  return { premium: Math.ceil(itemsTotal + surchargesTotal + PROCESSING_FEE) };
61	}
